<?php
$pageTitle='Create Project';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('projects');
$pdo=getDB();$scope=operationalScope($pdo);$scopeOptions=scopeSelectOptions($pdo);
$customers=$pdo->query('SELECT id,customer_code,company_name,contact_name FROM '.table('customers').' WHERE status="active" ORDER BY company_name,contact_name LIMIT 400')->fetchAll();
$users=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE status="active" AND (can_login_erp=1 OR role="admin") ORDER BY first_name,email LIMIT 300')->fetchAll();
$costCenters=$pdo->query('SELECT id,cost_center_code,cost_center_name FROM '.table('cost_centers').' WHERE status="active" ORDER BY cost_center_code')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $pdo->beginTransaction();
  try{
    $scope=['company_id'=>(int)($_POST['company_id']??$scope['company_id']),'branch_id'=>(int)($_POST['branch_id']??$scope['branch_id']),'warehouse_id'=>(int)setting('default_warehouse_id','0'),'location_id'=>(int)setting('default_location_id','0')];
    enforceScopeAllowed($pdo,$scope['company_id'],$scope['branch_id'],0,true);
    $number=nextScopedDocumentNumber($pdo,'project','PRJ',$scope);
    $customerId=(int)($_POST['customer_id']??0)?:null;$customerName=trim((string)($_POST['customer_name']??''));
    if($customerId){$s=$pdo->prepare('SELECT company_name,contact_name FROM '.table('customers').' WHERE id=?');$s->execute([$customerId]);$c=$s->fetch();if($c){$customerName=trim(($c['company_name']?:'').' '.($c['contact_name']?:''));}}
    $budget=max(0,(float)($_POST['budget_amount']??0));$revenue=max(0,(float)($_POST['revenue_amount']??0));
    $stmt=$pdo->prepare('INSERT INTO '.table('projects').' (company_id,branch_id,cost_center_id,project_number,project_name,customer_id,customer_name,project_manager_user_id,start_date,end_date,budget_amount,revenue_amount,cost_amount,margin_amount,status,description) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,0,?,"planning",?)');
    $stmt->execute([$scope['company_id']?:null,$scope['branch_id']?:null,(int)($_POST['cost_center_id']??0)?:null,$number,trim((string)($_POST['project_name']??'')),$customerId,$customerName,(int)($_POST['project_manager_user_id']??0)?:null,trim((string)($_POST['start_date']??''))?:null,trim((string)($_POST['end_date']??''))?:null,$budget,$revenue,round($revenue,2),trim((string)($_POST['description']??''))]);
    $id=(int)$pdo->lastInsertId();projectRecalculate($pdo,$id);logActivity($pdo,'Projects','project_created','Project '.$number.' created.','project',$id);
    $pdo->commit();flash('success','Project created.');redirect(ADMIN_URL.'/erp/view-project.php?id='.$id);
  }catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}flash('error',$e->getMessage());redirect(ADMIN_URL.'/erp/create-project.php');}
}
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Project Setup</div><h2 class="h4 mb-1">Create Project</h2><p class="text-secondary mb-0">Define project budget, revenue target, manager, customer, and cost center.</p></div><a class="btn btn-outline-secondary" href="<?php echo esc(ADMIN_URL); ?>/erp/projects.php">Back</a></div>
<form method="post" class="row g-4"><div class="col-xl-4"><div class="card-admin p-4"><h2 class="h5">Scope</h2><label class="form-label">Company</label><select class="form-select mb-2" name="company_id"><?php foreach($scopeOptions['companies'] as $company): ?><option value="<?php echo (int)$company['id']; ?>" <?php echo (int)$company['id']===(int)$scope['company_id']?'selected':''; ?>><?php echo esc($company['company_code'].' · '.$company['company_name']); ?></option><?php endforeach; ?></select><label class="form-label">Branch</label><select class="form-select mb-2" name="branch_id"><?php foreach($scopeOptions['branches'] as $branch): ?><option value="<?php echo (int)$branch['id']; ?>" <?php echo (int)$branch['id']===(int)$scope['branch_id']?'selected':''; ?>><?php echo esc($branch['branch_code'].' · '.$branch['branch_name']); ?></option><?php endforeach; ?></select><label class="form-label">Cost Center</label><select class="form-select mb-2" name="cost_center_id"><option value="0">None</option><?php foreach($costCenters as $cc): ?><option value="<?php echo (int)$cc['id']; ?>"><?php echo esc($cc['cost_center_code'].' · '.$cc['cost_center_name']); ?></option><?php endforeach; ?></select><label class="form-label">Manager</label><select class="form-select" name="project_manager_user_id"><option value="0">None</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select></div></div><div class="col-xl-8"><div class="card-admin p-4"><h2 class="h5">Project Details</h2><div class="row g-3"><div class="col-md-7"><label class="form-label">Project Name</label><input class="form-control" name="project_name" required></div><div class="col-md-5"><label class="form-label">Customer</label><select class="form-select" name="customer_id"><option value="0">Manual</option><?php foreach($customers as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['customer_code'].' · '.trim(($c['company_name']?:'').' '.($c['contact_name']?:''))); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Manual Customer</label><input class="form-control" name="customer_name"></div><div class="col-md-3"><label class="form-label">Start Date</label><input class="form-control" type="date" name="start_date"></div><div class="col-md-3"><label class="form-label">End Date</label><input class="form-control" type="date" name="end_date"></div><div class="col-md-6"><label class="form-label">Budget</label><input class="form-control" type="number" step="0.01" name="budget_amount"></div><div class="col-md-6"><label class="form-label">Revenue Target</label><input class="form-control" type="number" step="0.01" name="revenue_amount"></div><div class="col-12"><label class="form-label">Description</label><textarea class="form-control" rows="4" name="description"></textarea></div></div><button class="btn btn-brand mt-3">Create Project</button></div></div></form>
<?php include dirname(__DIR__).'/footer.php'; ?>